import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * Service for reading file content from the allowed base directory (/tmp/upload).
 * Ensures the requested path resolves within the base directory (prevents path traversal).
 */
public class FileService {

    private static final Logger LOGGER = Logger.getLogger(FileService.class.getName());
    private static final Path BASE_DIR = Paths.get("/tmp/upload").normalize().toAbsolutePath();

    /**
     * Reads the entire content of a text file using UTF-8 encoding.
     *
     * @param filePath The file path to read. Can be absolute (must be under /tmp/upload)
     *                 or relative to /tmp/upload.
     * @return The complete content of the file as a String.
     * @throws IOException If the file does not exist, is not readable, is outside the allowed
     *                     base directory, or an I/O error occurs.
     */
    public String readFileContent(String filePath) throws IOException {
        if (filePath == null || filePath.trim().isEmpty()) {
            throw new IOException("File path must not be null or empty.");
        }

        // Resolve and verify base directory exists
        final Path baseRealPath;
        try {
            baseRealPath = BASE_DIR.toRealPath(LinkOption.NOFOLLOW_LINKS);
        } catch (IOException e) {
            LOGGER.log(Level.WARNING, "Base directory does not exist or cannot be accessed: {0}", BASE_DIR);
            throw new IOException("Base directory does not exist or cannot be accessed: " + BASE_DIR, e);
        }

        // Resolve the requested path against the base directory
        Path requested = Paths.get(filePath.trim());
        Path candidate = requested.isAbsolute() ? requested : baseRealPath.resolve(requested);

        // Resolve the real path (follows symlinks) and ensure it exists
        final Path realPath;
        try {
            realPath = candidate.toRealPath(); // ensures existence and resolves symlinks
        } catch (IOException e) {
            LOGGER.log(Level.FINE, "Failed to resolve file path: {0}", candidate);
            throw new IOException("File not found or cannot be resolved: " + candidate, e);
        }

        // Security: ensure the resolved path is within the allowed base directory
        if (!realPath.startsWith(baseRealPath)) {
            LOGGER.log(Level.WARNING, "Access denied. Attempt to read outside base directory: {0}", realPath);
            throw new IOException("Access denied: path is outside the allowed directory.");
        }

        if (!Files.isRegularFile(realPath)) {
            throw new IOException("Path is not a regular file: " + realPath);
        }
        if (!Files.isReadable(realPath)) {
            throw new IOException("File is not readable: " + realPath);
        }

        // Read file content using UTF-8
        StringBuilder content = new StringBuilder();
        try (BufferedReader reader = Files.newBufferedReader(realPath, StandardCharsets.UTF_8)) {
            char[] buffer = new char[8192];
            int read;
            while ((read = reader.read(buffer)) != -1) {
                content.append(buffer, 0, read);
            }
        } catch (IOException e) {
            LOGGER.log(Level.WARNING, "I/O error while reading file: {0}", realPath);
            throw e;
        }

        return content.toString();
    }
}

